<?php if (!defined('ABSPATH')) exit; ?>
<div class="bg-white rounded-xl shadow-md p-6 sticky top-6"><h3 class="text-xl font-bold mb-4">Filtros</h3><form method="get"><div class="mb-4"><label class="block text-sm font-semibold mb-2">Nivel</label><select name="nivel" class="w-full px-4 py-2 border rounded-lg"><option value="">Todos</option><option value="principiante" <?php selected(isset($_GET['nivel']) ? $_GET['nivel'] : '', 'principiante'); ?>>Principiante</option><option value="intermedio" <?php selected(isset($_GET['nivel']) ? $_GET['nivel'] : '', 'intermedio'); ?>>Intermedio</option><option value="avanzado" <?php selected(isset($_GET['nivel']) ? $_GET['nivel'] : '', 'avanzado'); ?>>Avanzado</option></select></div><div class="mb-4"><label class="block text-sm font-semibold mb-2">Categoría</label><?php $cats = get_terms(array('taxonomy' => 'categoria_curso', 'hide_empty' => true)); if ($cats) : echo '<select name="categoria" class="w-full px-4 py-2 border rounded-lg"><option value="">Todas</option>'; foreach ($cats as $cat) echo '<option value="' . $cat->slug . '" ' . selected(isset($_GET['categoria']) ? $_GET['categoria'] : '', $cat->slug, false) . '>' . $cat->name . '</option>'; echo '</select>'; endif; ?></div><button type="submit" class="w-full px-4 py-2 bg-primary text-white rounded-lg">Filtrar</button></form></div>
